@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="Title" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="Assignee" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="OnCancel" disabled="@IsSaving">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="text-danger small mt-1">@ErrorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<AddTaskModel> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving { get; set; }
    private string? ErrorMessage { get; set; }

    private async Task HandleSave()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(Title))
        {
            ErrorMessage = "Title is required.";
            return;
        }

        IsSaving = true;
        try
        {
            await OnSave.InvokeAsync(new AddTaskModel(Title.Trim(), Assignee.Trim(), Priority, DueDate));
        }
        catch
        {
            ErrorMessage = "Failed to save task.";
        }
        finally
        {
            IsSaving = false;
        }
    }

    public record AddTaskModel(string Title, string Assignee, string Priority, DateTime DueDate);
}

@* A single Kanban column showing its header, task cards, and an add-task form toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Left))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Right))"
                          IsMoving="MovingTaskId == task.Id" />
            }

            @if (ShowAddForm)
            {
                <AddTaskForm OnSave="HandleAddTask" OnCancel="() => ShowAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-1" @onclick="() => ShowAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<AddTaskForm.AddTaskModel> OnAddTask { get; set; }
    [Parameter] public int? MovingTaskId { get; set; }

    private bool ShowAddForm { get; set; }

    private async Task HandleAddTask(AddTaskForm.AddTaskModel model)
    {
        await OnAddTask.InvokeAsync(model);
        ShowAddForm = false;
    }

    public enum MoveDirection { Left, Right }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title..."
           value="@SearchTerm" @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@using sv_357d770db97244b183e94d3a012e1ca2
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     ToDoCount="todoBucket.Count"
                     InProgressCount="inProgressBucket.Count"
                     DoneCount="doneBucket.Count"
                     OverdueCount="overdueCount" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredToDo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, \"To Do\")"
                     OnAddTask="model => HandleAddTask(model, \"To Do\")"
                     MovingTaskId="movingTaskId" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, \"In Progress\")"
                     OnAddTask="model => HandleAddTask(model, \"In Progress\")"
                     MovingTaskId="movingTaskId" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, \"Done\")"
                     OnAddTask="model => HandleAddTask(model, \"Done\")"
                     MovingTaskId="movingTaskId" />
    </div>
}

@code {
    private static readonly string[] ColumnOrder = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;
    private int? movingTaskId;

    // Unfiltered buckets (for summary counts)
    private List<TaskItem> todoBucket = new();
    private List<TaskItem> inProgressBucket = new();
    private List<TaskItem> doneBucket = new();
    private int overdueCount;

    // Filtered buckets (for display, respecting search)
    private List<TaskItem> filteredToDo = new();
    private List<TaskItem> filteredInProgress = new();
    private List<TaskItem> filteredDone = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync() ?? new();
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void RebuildBuckets()
    {
        todoBucket = allTasks.Where(t => t.Status == "To Do").ToList();
        inProgressBucket = allTasks.Where(t => t.Status == "In Progress").ToList();
        doneBucket = allTasks.Where(t => t.Status == "Done").ToList();
        overdueCount = allTasks.Count(t => t.DueDate < DateTime.Today);
        ApplySearchFilter();
    }

    private void ApplySearchFilter()
    {
        filteredToDo = Filter(todoBucket);
        filteredInProgress = Filter(inProgressBucket);
        filteredDone = Filter(doneBucket);
    }

    private List<TaskItem> Filter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;

        return tasks
            .Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
        ApplySearchFilter();
    }

    private async Task HandleMoveTask(int taskId, BoardColumn.MoveDirection direction, string currentStatus)
    {
        var currentIndex = Array.IndexOf(ColumnOrder, currentStatus);
        var newIndex = direction == BoardColumn.MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= ColumnOrder.Length)
            return;

        var newStatus = ColumnOrder[newIndex];

        movingTaskId = taskId;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);

            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks.Remove(task);
                allTasks.Add(task with { Status = newStatus });
                RebuildBuckets();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask(AddTaskForm.AddTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            // The service creates with default status; ensure it reflects the target column
            var withStatus = created with { Status = status };
            allTasks.Add(withStatus);
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

