toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@using sv_357d770db97244b183e94d3a012e1ca2
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="allTasks.Count"
                     ToDoCount="todoBucket.Count"
                     InProgressCount="inProgressBucket.Count"
                     DoneCount="doneBucket.Count"
                     OverdueCount="overdueCount" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredToDo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, &quot;To Do&quot;)"
                     OnAddTask="model => HandleAddTask(model, &quot;To Do&quot;)"
                     MovingTaskId="movingTaskId" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, &quot;In Progress&quot;)"
                     OnAddTask="model => HandleAddTask(model, &quot;In Progress&quot;)"
                     MovingTaskId="movingTaskId" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, &quot;Done&quot;)"
                     OnAddTask="model => HandleAddTask(model, &quot;Done&quot;)"
                     MovingTaskId="movingTaskId" />
    </div>
}

@code {
    private static readonly string[] ColumnOrder = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;
    private int? movingTaskId;

    private List<TaskItem> todoBucket = new();
    private List<TaskItem> inProgressBucket = new();
    private List<TaskItem> doneBucket = new();
    private int overdueCount;

    private List<TaskItem> filteredToDo = new();
    private List<TaskItem> filteredInProgress = new();
    private List<TaskItem> filteredDone = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync() ?? new();
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void RebuildBuckets()
    {
        todoBucket = allTasks.Where(t => t.Status == "To Do").ToList();
        inProgressBucket = allTasks.Where(t => t.Status == "In Progress").ToList();
        doneBucket = allTasks.Where(t => t.Status == "Done").ToList();
        overdueCount = allTasks.Count(t => t.DueDate < DateTime.Today);
        ApplySearchFilter();
    }

    private void ApplySearchFilter()
    {
        filteredToDo = Filter(todoBucket);
        filteredInProgress = Filter(inProgressBucket);
        filteredDone = Filter(doneBucket);
    }

    private List<TaskItem> Filter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;

        return tasks
            .Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
        ApplySearchFilter();
    }

    private async Task HandleMoveTask(int taskId, BoardColumn.MoveDirection direction, string currentStatus)
    {
        var currentIndex = Array.IndexOf(ColumnOrder, currentStatus);
        var newIndex = direction == BoardColumn.MoveDirection.Left ? currentIndex - 1 : currentIndex + 1;

        if (newIndex < 0 || newIndex >= ColumnOrder.Length)
            return;

        var newStatus = ColumnOrder[newIndex];

        movingTaskId = taskId;
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);

            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks.Remove(task);
                allTasks.Add(task with { Status = newStatus });
                RebuildBuckets();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleAddTask(AddTaskForm.AddTaskModel model, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            var withStatus = created with { Status = status };
            allTasks.Add(withStatus);
            RebuildBuckets();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

